            $this->assertEquals("text/html", trim($result->contentType));
            $this->assertNotEmpty($result->html);
            $this->assertEquals("Example Domain", trim(($result->getMetadata()->title ?? null)));
            $this->assertStringContainsString("illustrative examples", ($result->getMetadata()->description ?? null));
            $this->assertNotEmpty(($result->getMetadata()->canonicalUrl ?? null));
